{"code":"prs = github.list_pull_requests(state="open")
total = len(prs)
by_repo = {}
for p in prs:
    by_repo[p["repo"]] = by_repo.get(p["repo"], 0) + 1
top_repo, top_count = max(by_repo.items(), key=lambda kv: kv[1])
{"total_open": total, "by_repo": by_repo, "most_repo": top_repo, "most_count": top_count}
"}
